import { ReactNode } from "react";
import {
  ParsedField,
  ParsedSchema,
  Renderable,
  FieldConfig as BaseFieldConfig,
  SchemaProvider,
} from "@acp-autoform/core";

// Field binding contract
// Normalized shape every form-library adapter must return from useField().

export interface FieldBinding {
  value: any;
  onChange: (...event: any[]) => void;
  onBlur: () => void;
  name: string;
  /** ref is optional - not all adapters provide one */
  ref?: React.Ref<any>;
}

export interface UseFieldReturn {
  field: FieldBinding;
}

export type UseFieldFn = (opts: { name: string }) => UseFieldReturn;

// AutoForm props

export interface AutoFormProps<T extends Record<string, any> = Record<string, any>> {
  /** Schema adapter that manages fields, default values, and validation. */
  schema: SchemaProvider<T>;
  /**
   * External form control handle. For react-hook-form: the return of createFormControl().
   * For TanStack: the form instance returned by the adapter's useAppForm() in a parent.
   */
  formControl?: any;
  /**
   * Runs after successful validation. Receives the values and submit event.
   * @default () => {}
   */
  onSubmit?: (
    values: T,
    form: any,
    e?: React.BaseSyntheticEvent,
  ) => void | Promise<void>;
  /**
   * Initial values merged over schema defaults.
   * @default inferred from schema
   */
  defaultValues?: Partial<T>;
  /** Controlled values that keep the form in sync with external state. */
  values?: Partial<T>;
  /** Extra UI rendered after the generated fields. */
  children?: ReactNode;
  /** Layout/wrapper components for fields, errors, and structure. */
  uiComponents: AutoFormUIComponents;
  /** Form components mapped to field types (string, number, select, etc.). */
  formComponents: AutoFormFieldComponents;
  /**
   * Show a default submit button after all fields.
   * @default false
   */
  withSubmit?: boolean;
  /**
   * Legacy hook to access the form instance after init.
   * @deprecated Prefer passing an external form control via `formControl`.
   */
  onFormInit?: (form: any) => void;
  /**
   * Props forwarded to the underlying <form> element.
   * @default {}
   */
  formProps?: React.ComponentProps<"form"> | Record<string, any>;
}

export type AutoFormComponent = <
  T extends Record<string, any> = Record<string, any>,
>(props: AutoFormProps<T>) => React.ReactElement;

export type ExtendableAutoFormProps<T extends Record<string, any>> = Omit<
  AutoFormProps<T>,
  "uiComponents" | "formComponents"
> & {
  uiComponents?: Partial<AutoFormUIComponents>;
  formComponents?: Partial<AutoFormFieldComponents>;
};

// UI component contracts

export interface AutoFormUIComponents {
  /** Root form element. */
  Form: React.ComponentType<React.ComponentProps<"form">>;
  /** Wraps each field with label, error, and layout UI. */
  FieldWrapper: React.ComponentType<FieldWrapperProps>;
  /** Renders AutoForm configuration errors. */
  ErrorMessage: React.ComponentType<{ error: string }>;
  /** Submit button rendered when withSubmit is enabled. */
  SubmitButton: React.ComponentType<{ children: ReactNode }>;
  /** Wraps nested object fields. */
  ObjectWrapper: React.ComponentType<ObjectWrapperProps>;
  /** Wraps array fields and owns the add-item action. */
  ArrayWrapper: React.ComponentType<ArrayWrapperProps>;
  /** Wraps one array item and owns the remove-item action. */
  ArrayElementWrapper: React.ComponentType<ArrayElementWrapperProps>;
}

export interface AutoFormFieldComponents {
  [key: string]: React.ComponentType<AutoFormFieldProps>;
}

// Wrapper prop types

export interface FieldWrapperProps {
  label: Renderable<ReactNode>;
  error?: Renderable<ReactNode>;
  children: ReactNode;
  id: string;
  parsedField: ParsedField;
}

export interface ArrayWrapperProps {
  label: Renderable<ReactNode>;
  error?: Renderable<ReactNode>;
  children: ReactNode;
  inputProps: any;
  parsedField: ParsedField;
  onAddItem: () => void;
}

export interface ArrayElementWrapperProps {
  children: ReactNode;
  onRemove: () => void;
  index: number;
}

export interface ObjectWrapperProps {
  label: Renderable<ReactNode>;
  children: ReactNode;
  parsedField: ParsedField;
}

// Field component props

export interface AutoFormFieldProps {
  path: string[];
  id: string;
  error?: string;
  parsedField: ParsedField;
  label: Renderable<ReactNode>;
  inputProps: any;
}

// Context type

export interface AutoFormContextType {
  schema: ParsedSchema;
  uiComponents: AutoFormUIComponents;
  formComponents: AutoFormFieldComponents;
  /** The useField implementation injected by the active form library adapter. */
  useField: UseFieldFn;
}

// FieldConfig

export type FieldConfig<
  FieldTypes = string,
  CustomData = Record<string, any>,
  FieldWrapper = React.ComponentType<FieldWrapperProps>,
  ObjectWrapper = React.ComponentType<ObjectWrapperProps>,
  ArrayWrapper = React.ComponentType<ArrayWrapperProps>,
  ArrayElementWrapper = React.ComponentType<ArrayElementWrapperProps>,
> = BaseFieldConfig<
  ReactNode,
  FieldTypes,
  CustomData,
  FieldWrapper,
  ObjectWrapper,
  ArrayWrapper,
  ArrayElementWrapper
>;

// Re-exports

export type { SchemaProvider, ParsedField, ParsedSchema } from "@acp-autoform/core";

import { createContext, useContext } from "react";
import { AutoFormContextType, UseFieldReturn } from "./types";

const AutoFormContext = createContext<AutoFormContextType | null>(null);

export const AutoFormProvider = AutoFormContext.Provider;

export function useAutoForm() {
  const context = useContext(AutoFormContext);
  if (!context) {
    throw new Error("useAutoForm must be used within an AutoFormProvider");
  }
  return context;
}

/**
 * Context-delegating useField hook.
 * UI components call this. The actual implementation is injected by whichever
 * form library adapter (./react-hook-form or ./tanstack-form) wraps the tree.
 */
export function useField(opts: { name: string }): UseFieldReturn {
  const { useField: impl } = useAutoForm();
  return impl(opts);
}

import type { ParsedField } from "@acp-autoform/core";

export function getArrayItemDefaultValue(parsedField: ParsedField): any {
  const itemField = parsedField.schema?.[0];
  if (!itemField) return null;
  if (itemField.default !== undefined) return itemField.default;
  if (itemField.type === "object") return getObjectDefaultValue(itemField);
  if (itemField.type === "array") return [];
  return null;
}

function getObjectDefaultValue(parsedField: ParsedField): Record<string, any> {
  const value: Record<string, any> = {};

  for (const child of parsedField.schema ?? []) {
    if (child.default !== undefined) {
      value[child.key] = child.default;
    } else if (child.required && child.type === "object") {
      value[child.key] = getObjectDefaultValue(child);
    } else if (child.required && child.type === "array") {
      value[child.key] = [];
    }
  }

  return value;
}

"use client";

// Shared adapter-agnostic root. Runtime form implementations live only in
// ./react-hook-form and ./tanstack-form so consumers can bundle one adapter.
export * from "./types";
export * from "./context";

"use client";

export * from "./AutoForm";
export * from "./AutoFormField";
export * from "./ArrayField";
export * from "./ObjectField";
export * from "./useFieldError";
export * from "./utils";
// Re-export the shared root without creating another context instance.
export * from "../types";
export * from "../context";

import { useEffect, useRef } from "react";
import {
  useForm,
  FieldValues,
  FormProvider,
  SubmitHandler,
  SubmitErrorHandler,
  DefaultValues,
  useController,
} from "react-hook-form";
import { getDefaultValues, parseSchema } from "@acp-autoform/core";
import type { AutoFormProps, UseFieldFn } from "../types";
import { AutoFormProvider } from "../context";
import { AutoFormField } from "./AutoFormField";
import { createSchemaResolver, focusFirstInvalidInput, preventPropagation } from "./utils";

/**
 * RHF-backed useField implementation.
 * Normalizes useController return to the shared FieldBinding shape.
 */
const useFieldRHF: UseFieldFn = ({ name }) => {
  const { field } = useController({ name });
  return { field };
};

export function AutoForm<T extends FieldValues = FieldValues>({
  formControl,
  schema,
  onSubmit = () => {},
  values,
  defaultValues,
  children,
  uiComponents,
  formComponents,
  withSubmit = false,
  onFormInit,
  formProps = {},
}: AutoFormProps<T>) {
  const shouldFocusError = useRef(
    formControl?.control?._options?.shouldFocusError !== false,
  ).current;
  const { ref: _ref, ...restFormProps } = formProps as React.ComponentProps<"form">;
  const parsedSchema = parseSchema(schema);
  const resolver = createSchemaResolver(schema);

  const methods = useForm<T, any, T>({
    resolver,
    defaultValues: {
      ...(getDefaultValues(schema) as Partial<T>),
      ...defaultValues,
    } as DefaultValues<T>,
    values: values as T,
    formControl,
    shouldFocusError: false,
  });

  useEffect(() => {
    onFormInit?.(methods);
  }, [methods, onFormInit]);

  const handleSubmit: SubmitHandler<T> = async (data: T, e) => {
    await onSubmit(data, methods, e);
  };

  const handleError: SubmitErrorHandler<T> = () => {
    if (shouldFocusError) {
      focusFirstInvalidInput();
    }
  };

  return (
    <FormProvider {...methods}>
      <AutoFormProvider
        value={{
          schema: parsedSchema,
          uiComponents,
          formComponents,
          useField: useFieldRHF,
        }}
      >
        <uiComponents.Form
          onSubmit={preventPropagation(
            methods.handleSubmit(handleSubmit, handleError),
          )}
          ref={_ref}
          {...restFormProps}
        >
          {parsedSchema.fields.map((field) => (
            <AutoFormField
              key={field.key}
              parsedField={field}
              path={[field.key]}
            />
          ))}
          {withSubmit && (
            <uiComponents.SubmitButton>Submit</uiComponents.SubmitButton>
          )}
          {children}
        </uiComponents.Form>
      </AutoFormProvider>
    </FormProvider>
  );
}

import React from "react";
import { getLabel, ParsedField } from "@acp-autoform/core";
import { useAutoForm } from "../context";
import { useFieldError } from "./useFieldError";
import { ArrayField } from "./ArrayField";
import { ObjectField } from "./ObjectField";
import type { AutoFormFieldProps } from "../types";

export const AutoFormField: React.FC<{
  parsedField: ParsedField;
  path: string[];
}> = ({ path, parsedField }) => {
  const { formComponents, uiComponents } = useAutoForm();
  const error = useFieldError(path);

  const fullPath = path.join(".");
  const fieldConfig = parsedField.fieldConfig;
  const FieldWrapper = fieldConfig?.fieldWrapper || uiComponents.FieldWrapper;

  let FieldComponent: React.ComponentType<AutoFormFieldProps>;
  if (parsedField.type === "array") {
    FieldComponent = ArrayField;
  } else if (parsedField.type === "object") {
    FieldComponent = ObjectField;
  } else if (parsedField.type in formComponents) {
    FieldComponent =
      formComponents[parsedField.type as keyof typeof formComponents]!;
  } else if ("fallback" in formComponents) {
    FieldComponent = formComponents.fallback;
  } else {
    FieldComponent = () => (
      <uiComponents.ErrorMessage
        error={`[AutoForm Configuration Error] No component found for type "${parsedField.type}" nor a fallback`}
      />
    );
  }

  return (
    <FieldWrapper
      label={getLabel(parsedField)}
      error={error}
      id={fullPath}
      parsedField={parsedField}
    >
      <FieldComponent
        key={`${fullPath}-input`}
        path={path}
        id={fullPath}
        error={error}
        parsedField={parsedField}
        label={getLabel(parsedField)}
        inputProps={{
          ...fieldConfig?.inputProps,
          "aria-invalid": !!error || undefined,
        }}
      />
    </FieldWrapper>
  );
};

import React from "react";
import { useFieldArray } from "react-hook-form";
import { getLabel, ParsedField } from "@acp-autoform/core";
import { AutoFormField } from "./AutoFormField";
import { useAutoForm } from "../context";
import { useRegister } from "./utils";
import { getArrayItemDefaultValue } from "../utils";

export const ArrayField: React.FC<{
  id: string;
  path: string[];
  inputProps: any;
  parsedField: ParsedField;
  error?: string | undefined;
}> = ({ id, path, inputProps, error, parsedField }) => {
  const { uiComponents } = useAutoForm();
  const { fields, append, remove } = useFieldArray({
    name: path.join("."),
  });
  const ref = useRegister(path.join(".")).ref;
  const ArrayWrapper =
    parsedField.fieldConfig?.arrayWrapper || uiComponents.ArrayWrapper;
  const ArrayElementWrapper =
    parsedField.fieldConfig?.arrayElementWrapper ||
    uiComponents.ArrayElementWrapper;
  const defaultValue = getArrayItemDefaultValue(parsedField);

  return (
    <ArrayWrapper
      error={error}
      parsedField={parsedField}
      inputProps={{
        key: `${id}-input`,
        ...inputProps,
        ref: ref,
      }}
      label={getLabel(parsedField)}
      onAddItem={() => append(defaultValue)}
    >
      {fields.map((item, index) => (
        <ArrayElementWrapper
          key={item.id}
          onRemove={() => remove(index)}
          index={index}
        >
          <AutoFormField
            parsedField={parsedField.schema![0]!}
            path={[...path, index.toString()]}
          />
        </ArrayElementWrapper>
      ))}
    </ArrayWrapper>
  );
};

import React from "react";
import { AutoFormField } from "./AutoFormField";
import { useAutoForm } from "../context";
import { getLabel, ParsedField } from "@acp-autoform/core";

export const ObjectField: React.FC<{
  parsedField: ParsedField;
  path: string[];
}> = ({ path, parsedField }) => {
  const { uiComponents } = useAutoForm();
  const ObjectWrapper =
    parsedField.fieldConfig?.objectWrapper || uiComponents.ObjectWrapper;

  return (
    <ObjectWrapper label={getLabel(parsedField)} parsedField={parsedField}>
      {Object.entries(parsedField.schema!).map(([_key, subField]) => (
        <AutoFormField
          key={`${path.join(".")}.${subField.key}`}
          parsedField={subField}
          path={[...path, subField.key]}
        />
      ))}
    </ObjectWrapper>
  );
};

import { useEffect, useState } from "react";
import { useFormContext, useFormState } from "react-hook-form";
import type { UseFormReturn, FieldValues } from "react-hook-form";
import { getPathInObject } from "./utils";

export const useFieldError = (path: string[]) => {
  const { subscribe } = useFormContext();

  if (typeof subscribe !== "function") {
    return useFieldErrorFallback(path);
  }

  return useFieldErrorSubscribe(path, subscribe);
};

const useFieldErrorSubscribe = (
  path: string[],
  subscribe: UseFormReturn<FieldValues>["subscribe"],
) => {
  const [error, setError] = useState<string | undefined>(undefined);
  const fieldPath = path.join(".");

  useEffect(() => {
    const callback = subscribe({
      formState: {
        errors: true,
      },
      callback: ({ errors }) => {
        const newError = getPathInObject(errors, path)?.message as
          | string
          | undefined;
        setError((prev) => (prev !== newError ? newError : prev));
      },
    });

    return () => callback();
  }, [fieldPath, subscribe]);

  return error;
};

const useFieldErrorFallback = (path: string[]) => {
  const fieldPath = path.join(".");
  const { errors } = useFormState({
    name: fieldPath as any,
    exact: true,
  });

  return getPathInObject(errors, path)?.message as string | undefined;
};

import { SchemaProvider, replaceEmptyValue } from "@acp-autoform/core";
import React from "react";
import {
  FieldValues,
  Resolver,
  ResolverOptions,
  ResolverResult,
  useFormContext,
  UseFormRegister,
} from "react-hook-form";

/**
 * Focus the first input element marked as invalid.
 * Used by both RHF (onError) and TanStack (onSubmitInvalid) adapters.
 * AutoFormField auto-injects aria-invalid into inputProps.
 */
export function focusFirstInvalidInput(): void {
  setTimeout(() => {
    // Find the first element marked as invalid natively or via our data attribute
    // Using a combined selector ensures we find the first one in document order
    const firstInvalid = document.querySelector<HTMLElement>(
      '[aria-invalid="true"]'
    );

    if (!firstInvalid) return;

    // If the element itself is directly focusable, focus it
    if (
      firstInvalid.tagName === "INPUT" ||
      firstInvalid.tagName === "SELECT" ||
      firstInvalid.tagName === "TEXTAREA" ||
      firstInvalid.tagName === "BUTTON" ||
      firstInvalid.hasAttribute("tabindex")
    ) {
      firstInvalid.focus();
      return;
    }

    // Otherwise, it's a wrapper, find the first focusable input inside it
    const input = firstInvalid.querySelector<HTMLElement>(
      'input, button, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    if (input) {
      input.focus();
    } else {
      firstInvalid.scrollIntoView({ behavior: "smooth", block: "center" });
    }
  }, 50);
}

/**
 * This custom hook shares the same props and methods as register.
 * @returns Return value of `register`
 */
export function useRegister<TFieldValues extends FieldValues = FieldValues>(
  ...props: Parameters<UseFormRegister<TFieldValues>>
) {
  const { register } = useFormContext<TFieldValues>();
  return register(...props);
}

/**
 * Retrieves the error of a field using given error object and field path.
 */
export function getPathInObject(obj: any, path: string[]): any {
  let current = obj;
  for (const key of path) {
    current = current[key];
    if (current === undefined) {
      return undefined;
    }
  }
  return current.message ? current : (current.root ?? current);
}

/**
 * Wraps the form submit handler to stop event propagation before executing.
 */
export const preventPropagation =
  (callback: (e: React.FormEvent<HTMLFormElement>) => void | Promise<void>) =>
  async (e: React.FormEvent<HTMLFormElement>) => {
    e.stopPropagation();
    await callback(e);
  };

/**
 * Creates a React Hook Form resolver for an AutoForm schema provider.
 */
export function createSchemaResolver<T extends FieldValues>(
  schema: SchemaProvider<T>,
): Resolver<T> {
  let resolverPromise: Promise<Resolver<T>> | undefined;

  return async (
    values: T,
    ctx: any,
    options: ResolverOptions<T>,
  ): Promise<ResolverResult<T>> => {
    const cleanedValues = replaceEmptyValue(values);
    resolverPromise ??= getSchemaResolver(schema);
    const resolver = await resolverPromise;
    return resolver(cleanedValues, ctx, options);
  };
}

async function getSchemaResolver<T extends FieldValues>(
  schema: SchemaProvider<T>,
): Promise<Resolver<T>> {
    const rawSchema = schema.getSchema?.();
  if (!schema.schemaType || !rawSchema) {
    throw new Error(
      "AutoForm: schema provider must expose schemaType and getSchema() " +
        "to use resolver validation.",
    );
  }

  switch (schema.schemaType) {
    case "zod": {
      const { zodResolver } = await import("@hookform/resolvers/zod");
      return zodResolver(rawSchema as any) as Resolver<T>;
    }
    case "yup": {
      const { yupResolver } = await import("@hookform/resolvers/yup");
      return yupResolver(rawSchema as any) as Resolver<T>;
    }
    case "joi": {
      const { joiResolver } = await import("@hookform/resolvers/joi");
      return joiResolver(rawSchema as any) as Resolver<T>;
    }
  }

  throw new Error(`AutoForm: unsupported schema type "${schema.schemaType}".`);
}
